 17	/// Parse a tmux-style string.
 18	/// Formats: "fg=red,bg=blue,bold" or "fg=colour196,bold,italics"
 19	pub fn parse(s: []const u8) Style {
 20	    var style = Style.default;
 21	    var remaining = s;
 22	
 23	    // Strip #[ prefix and ] suffix if present
 24	    if (std.mem.startsWith(u8, remaining, "#[")) {
 25	        remaining = remaining[2..];
 26	        if (remaining.len > 0 and remaining[remaining.len - 1] == ']') {
 27	            remaining = remaining[0 .. remaining.len - 1];
 28	        }
 29	    }
 30	
 31	    var iter = std.mem.splitScalar(u8, remaining, ',');
 32	    while (iter.next()) |part| {
 33	        const trimmed = std.mem.trim(u8, part, " ");
 34	        if (trimmed.len == 0) continue;
 35	
 36	        if (std.mem.startsWith(u8, trimmed, "fg=")) {
 37	            if (colour.Colour.parse(trimmed[3..])) |c| {
 38	                style.fg = c;
 39	            }
 40	        } else if (std.mem.startsWith(u8, trimmed, "bg=")) {
 41	            if (colour.Colour.parse(trimmed[3..])) |c| {
 42	                style.bg = c;
 43	            }
 44	        } else if (std.mem.eql(u8, trimmed, "bold")) {
 45	            style.attrs.bold = true;
 46	        } else if (std.mem.eql(u8, trimmed, "dim")) {
 47	            style.attrs.dim = true;
 48	        } else if (std.mem.eql(u8, trimmed, "italics") or std.mem.eql(u8, trimmed, "italic")) {
 49	            style.attrs.italic = true;
 50	        } else if (std.mem.eql(u8, trimmed, "underscore") or std.mem.eql(u8, trimmed, "underline")) {
 51	            style.attrs.underline = true;
 52	        } else if (std.mem.eql(u8, trimmed, "blink")) {
 53	            style.attrs.blink = true;
 54	        } else if (std.mem.eql(u8, trimmed, "reverse")) {
 55	            style.attrs.reverse = true;
 56	        } else if (std.mem.eql(u8, trimmed, "hidden")) {
 57	            style.attrs.hidden = true;
 58	        } else if (std.mem.eql(u8, trimmed, "strikethrough")) {
 59	            style.attrs.strikethrough = true;
 60	        } else if (std.mem.eql(u8, trimmed, "overline")) {
 61	            style.attrs.overline = true;
 62	        } else if (std.mem.eql(u8, trimmed, "default") or std.mem.eql(u8, trimmed, "none")) {
 63	            style = Style.default;
 64	        } else if (std.mem.eql(u8, trimmed, "nobold")) {
 65	            style.attrs.bold = false;
 66	        } else if (std.mem.eql(u8, trimmed, "nodim")) {
 67	            style.attrs.dim = false;
 68	        } else if (std.mem.eql(u8, trimmed, "noitalics")) {
 69	            style.attrs.italic = false;
 70	        } else if (std.mem.eql(u8, trimmed, "nounderscore")) {
 71	            style.attrs.underline = false;
 72	        } else if (std.mem.eql(u8, trimmed, "noblink")) {
 73	            style.attrs.blink = false;
 74	        } else if (std.mem.eql(u8, trimmed, "noreverse")) {
 75	            style.attrs.reverse = false;
 76	        }
 77	    }
 78	
 79	    return style;
